import{_ as i,o,c as a,ag as t}from"./chunks/framework.eQLvDOR_.js";const u=JSON.parse('{"title":"llm-augmented-wiki","description":"","frontmatter":{"title":"llm-augmented-wiki","concept":"LLM Augmented Wiki","concept_id":"llm-augmented-wiki","aliases":["LLM-Wiki","知识图谱-Wiki"],"sources":["02_Library/NotebookLM_Workflows/[NotebookLM_Workflows] llm-wiki.md"],"related_concepts":["[[wiki-automated-generation]]"],"created_at":"2026-04-07","last_compiled":"2026-04-07"},"headers":[],"relativePath":"wiki/concepts/llm-augmented-wiki.md","filePath":"wiki/concepts/llm-augmented-wiki.md","lastUpdated":null}'),l={name:"wiki/concepts/llm-augmented-wiki.md"};function r(n,e,s,d,c,m){return o(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="llm-augmented-wiki-llm-增强知识库" tabindex="-1">LLM Augmented Wiki (LLM 增强知识库) <a class="header-anchor" href="#llm-augmented-wiki-llm-增强知识库" aria-label="Permalink to &quot;LLM Augmented Wiki (LLM 增强知识库)&quot;">​</a></h1><h2 id="设计架构" tabindex="-1">设计架构 <a class="header-anchor" href="#设计架构" aria-label="Permalink to &quot;设计架构&quot;">​</a></h2><p>一种专为人类阅读和 LLM 检索同时优化的知识管理结构。</p><h2 id="三层模型" tabindex="-1">三层模型 <a class="header-anchor" href="#三层模型" aria-label="Permalink to &quot;三层模型&quot;">​</a></h2><ol><li><strong>01_Inbox</strong>：原始剪藏 (Raw Clips)，保持原状，用于存档和回溯。</li><li><strong>02_Library</strong>：初步分类 (Distilled Library)，进行元数据标准化，方便初步检索。</li><li><strong>03_Wiki</strong>：概念中心 (Concept-Centric Wiki)，将零散信息重组为结构化概念块。</li></ol><h2 id="对-llm-的友好性设计" tabindex="-1">对 LLM 的友好性设计 <a class="header-anchor" href="#对-llm-的友好性设计" aria-label="Permalink to &quot;对 LLM 的友好性设计&quot;">​</a></h2><ul><li><strong>原子性</strong>：每个 Concept 文件只讲一个核心概念。</li><li><strong>关联性</strong>：大量使用 <code>[](/wiki/concepts/)</code> 链接，形成非线性的知识图谱，便于 LLM 进行多跳搜索。</li><li><strong>扁平化目录</strong>：减少文件夹深度，方便 <code>grep</code> 快速定位。</li></ul><h2 id="演进方向" tabindex="-1">演进方向 <a class="header-anchor" href="#演进方向" aria-label="Permalink to &quot;演进方向&quot;">​</a></h2><p>知识库不仅是静态文档，而应作为 Agent 的“外部大脑”的一部分，通过 <code>/query-wiki</code> 命令快速生成研究报告或技术选型建议。</p><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>元数据自动化</strong>：为 Library 中的文章添加 <code>tags</code>, <code>source_url</code> 和 <code>topics</code>，这是 LLM 进行准确检索的基础。</li><li><strong>冲突处理</strong>：当两个 Wiki 概念库发生碰撞时，使用 <code>/merge-concepts</code> 技能自动执行 MD 知识合并，而非手动剪贴。</li><li><strong>定期 Lint</strong>：每月运行一次全站链接检查，确保图谱中没有“孤儿页面”。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/NotebookLM_Workflows/NotebookLM_Workflows - llm-wiki.html">[NotebookLM_Workflows] llm-wiki</a></li></ul>',15)])])}const h=i(l,[["render",r]]);export{u as __pageData,h as default};
